// VersionParser — reads and writes version strings in both plain version.txt
// and package.json formats.
// GREEN phase: minimum implementation to make VersionParserTests pass.

using System.Text.Json;
using System.Text.RegularExpressions;

namespace VersionBumper;

/// <summary>
/// Parses and updates semantic version strings embedded in version files.
/// Supports two file types:
///   - Plain text (*.txt, VERSION, etc.) — the whole file is the version string.
///   - package.json — the "version" JSON field is read/written.
/// </summary>
public static class VersionParser
{
    // Regex to match the "version" field in package.json (handles whitespace variants)
    private static readonly Regex PackageVersionRegex = new(
        @"""version""\s*:\s*""(\d+\.\d+\.\d+)""",
        RegexOptions.Compiled | RegexOptions.IgnoreCase);

    /// <summary>
    /// Parse a <see cref="SemanticVersion"/> from the given file <paramref name="content"/>.
    /// The <paramref name="fileName"/> is used only to choose the parsing strategy
    /// (package.json vs plain text).
    /// </summary>
    public static SemanticVersion Parse(string content, string fileName)
    {
        return IsPackageJson(fileName)
            ? ParseFromPackageJson(content)
            : SemanticVersion.Parse(content.Trim());
    }

    /// <summary>
    /// Return a new copy of <paramref name="content"/> with the version replaced
    /// by <paramref name="newVersion"/>.
    /// For plain text files the entire content is replaced.
    /// For package.json only the "version" field value is replaced.
    /// </summary>
    public static string UpdateContent(string content, string fileName, SemanticVersion newVersion)
    {
        return IsPackageJson(fileName)
            ? UpdatePackageJson(content, newVersion)
            : newVersion.ToString();
    }

    // ─────────────────────────────────────────────────────
    // Async file-level helpers
    // ─────────────────────────────────────────────────────

    /// <summary>Read a version file from disk and parse it.</summary>
    public static async Task<SemanticVersion> ParseFileAsync(string filePath)
    {
        var content = await File.ReadAllTextAsync(filePath);
        return Parse(content, Path.GetFileName(filePath));
    }

    /// <summary>Read a version file, update the version, and write it back.</summary>
    public static async Task UpdateFileAsync(string filePath, SemanticVersion newVersion)
    {
        var content = await File.ReadAllTextAsync(filePath);
        var updated = UpdateContent(content, Path.GetFileName(filePath), newVersion);
        await File.WriteAllTextAsync(filePath, updated);
    }

    // ─────────────────────────────────────────────────────
    // Private helpers
    // ─────────────────────────────────────────────────────

    private static bool IsPackageJson(string fileName) =>
        Path.GetFileName(fileName).Equals("package.json", StringComparison.OrdinalIgnoreCase);

    private static SemanticVersion ParseFromPackageJson(string content)
    {
        using var doc = JsonDocument.Parse(content);

        if (!doc.RootElement.TryGetProperty("version", out var versionElement))
            throw new InvalidOperationException(
                "package.json does not contain a 'version' field. " +
                "Ensure the file has a top-level \"version\" key.");

        var versionStr = versionElement.GetString()
            ?? throw new InvalidOperationException(
                "'version' field in package.json is null. Expected a semver string like \"1.0.0\".");

        return SemanticVersion.Parse(versionStr);
    }

    private static string UpdatePackageJson(string content, SemanticVersion newVersion)
    {
        // Use regex replacement to preserve all other formatting
        if (!PackageVersionRegex.IsMatch(content))
            throw new InvalidOperationException(
                "Could not find a 'version' field to update in package.json.");

        return PackageVersionRegex.Replace(
            content,
            $@"""version"": ""{newVersion}""");
    }
}

// CommitAnalyzer — parses conventional commit messages and determines the
// required version bump type.
// GREEN phase: minimum implementation to make CommitAnalyzerTests pass.

using System.Text.RegularExpressions;

namespace VersionBumper;

/// <summary>
/// Analyses a list of conventional commit messages to determine the required
/// <see cref="BumpType"/>.
///
/// Conventional Commits spec: https://www.conventionalcommits.org/
///   type(scope)!: description
///   [optional body containing "BREAKING CHANGE: ..."]
///
/// Bump rules:
///   BREAKING CHANGE (! or body keyword)  → Major
///   feat                                 → Minor
///   fix / perf                           → Patch
///   everything else                      → None
/// </summary>
public static class CommitAnalyzer
{
    // Matches:  type(optional scope)optional!: description
    // Groups:   type | scope | breaking | description
    private static readonly Regex ConventionalPattern = new(
        @"^(?<type>[a-zA-Z]+)(?:\((?<scope>[^)]+)\))?(?<breaking>!)?\s*:\s*(?<description>.+)$",
        RegexOptions.Compiled);

    // Matches "BREAKING CHANGE:" or "BREAKING-CHANGE:" anywhere in the message body
    private static readonly Regex BreakingBodyPattern = new(
        @"BREAKING[\s\-]CHANGE\s*:",
        RegexOptions.Compiled | RegexOptions.IgnoreCase);

    // ─────────────────────────────────────────────────────
    // Public API
    // ─────────────────────────────────────────────────────

    /// <summary>
    /// Parse a single conventional commit message into a <see cref="Commit"/> record.
    /// Non-conventional messages are returned with Type = "other".
    /// </summary>
    public static Commit ParseCommit(string message)
    {
        if (string.IsNullOrWhiteSpace(message))
            return new Commit("other", message ?? "", false, Body: message);

        // The conventional commit subject is always the first line
        var firstLine = message.Split('\n')[0].Trim();
        var match = ConventionalPattern.Match(firstLine);

        if (!match.Success)
            return new Commit("other", firstLine, false, Body: message);

        var type        = match.Groups["type"].Value.ToLowerInvariant();
        var scope       = match.Groups["scope"].Success ? match.Groups["scope"].Value : null;
        var description = match.Groups["description"].Value.Trim();

        // Breaking if "!" appears after the type/scope OR "BREAKING CHANGE:" is in the body
        var isBreaking = match.Groups["breaking"].Success
                      || BreakingBodyPattern.IsMatch(message);

        return new Commit(type, description, isBreaking, scope, message);
    }

    /// <summary>
    /// Parse a collection of commit messages into <see cref="Commit"/> records.
    /// </summary>
    public static IReadOnlyList<Commit> ParseCommits(IEnumerable<string> messages)
        => messages.Select(ParseCommit).ToList().AsReadOnly();

    /// <summary>
    /// Analyse a collection of commit messages and return the highest
    /// <see cref="BumpType"/> required.  Major > Minor > Patch > None.
    /// </summary>
    public static BumpType AnalyzeCommits(IEnumerable<string> messages)
    {
        var result = BumpType.None;

        foreach (var message in messages)
        {
            var commit    = ParseCommit(message);
            var commitBump = GetBumpType(commit);

            // Keep the highest bump encountered
            if (commitBump > result)
                result = commitBump;

            // Short-circuit: nothing can exceed Major
            if (result == BumpType.Major)
                return result;
        }

        return result;
    }

    // ─────────────────────────────────────────────────────
    // Private helpers
    // ─────────────────────────────────────────────────────

    private static BumpType GetBumpType(Commit commit)
    {
        // Breaking change always wins regardless of type
        if (commit.IsBreaking)
            return BumpType.Major;

        return commit.Type switch
        {
            "feat"  => BumpType.Minor,
            "fix"   => BumpType.Patch,
            "perf"  => BumpType.Patch, // performance fixes are patch-level
            _       => BumpType.None   // chore, docs, style, test, refactor, etc.
        };
    }
}

