// ChangelogGenerator — produces a Keep-a-Changelog-style markdown section
// for a new release.
// GREEN phase: minimum implementation to make ChangelogGeneratorTests pass.

using System.Text;

namespace VersionBumper;

/// <summary>
/// Generates a markdown changelog entry for a release.
///
/// Output format follows Keep a Changelog (https://keepachangelog.com/):
///
///   ## [MAJOR.MINOR.PATCH] - YYYY-MM-DD
///
///   ### BREAKING CHANGES
///   - **scope**: description ⚠️ BREAKING
///
///   ### Features
///   - **scope**: description
///
///   ### Bug Fixes
///   - description
///
/// Only sections that have commits are included.
/// </summary>
public static class ChangelogGenerator
{
    /// <summary>
    /// Generate a changelog entry.
    /// </summary>
    /// <param name="version">The new version being released.</param>
    /// <param name="commits">Parsed commits included in this release.</param>
    /// <param name="date">Release date (defaults to UTC today if null).</param>
    public static string Generate(
        SemanticVersion version,
        IEnumerable<Commit> commits,
        DateTime? date = null)
    {
        var releaseDate = date ?? DateTime.UtcNow;
        var commitList = commits.ToList();

        var sb = new StringBuilder();
        sb.AppendLine($"## [{version}] - {releaseDate:yyyy-MM-dd}");

        // Partition commits into categories
        var breaking  = commitList.Where(c => c.IsBreaking).ToList();
        var features  = commitList.Where(c => !c.IsBreaking && c.Type == "feat").ToList();
        var fixes     = commitList.Where(c => !c.IsBreaking && c.Type == "fix").ToList();
        var other     = commitList.Where(c => !c.IsBreaking
                                           && c.Type != "feat"
                                           && c.Type != "fix"
                                           && c.Type != "other").ToList();

        AppendSection(sb, "BREAKING CHANGES", breaking);
        AppendSection(sb, "Features",         features);
        AppendSection(sb, "Bug Fixes",        fixes);
        AppendSection(sb, "Other Changes",    other);

        return sb.ToString().TrimEnd() + Environment.NewLine;
    }

    // ─────────────────────────────────────────────────────
    // Private helpers
    // ─────────────────────────────────────────────────────

    private static void AppendSection(StringBuilder sb, string title, List<Commit> commits)
    {
        if (commits.Count == 0) return;

        sb.AppendLine();
        sb.AppendLine($"### {title}");
        sb.AppendLine();
        foreach (var commit in commits)
            sb.AppendLine($"- {FormatCommit(commit)}");
    }

    private static string FormatCommit(Commit commit)
    {
        // Prefix with bold scope if present
        var prefix = commit.Scope is not null ? $"**{commit.Scope}**: " : string.Empty;
        // Append a visual warning marker for breaking changes
        var suffix = commit.IsBreaking ? " ⚠️ BREAKING" : string.Empty;
        return $"{prefix}{commit.Description}{suffix}";
    }
}

// Domain models for the semantic version bumper.
// These are the core types shared across all components.

namespace VersionBumper;

/// <summary>
/// Immutable semantic version (MAJOR.MINOR.PATCH).
/// Uses record for value equality — two SemanticVersion instances
/// with the same numbers are considered equal.
/// </summary>
public record SemanticVersion(int Major, int Minor, int Patch)
{
    /// <summary>Returns "MAJOR.MINOR.PATCH" string representation.</summary>
    public override string ToString() => $"{Major}.{Minor}.{Patch}";

    /// <summary>
    /// Parse a "MAJOR.MINOR.PATCH" string into a SemanticVersion.
    /// Throws <see cref="FormatException"/> if the input is not a valid semver.
    /// </summary>
    public static SemanticVersion Parse(string version)
    {
        if (string.IsNullOrWhiteSpace(version))
            throw new FormatException($"Invalid semantic version: '{version}'. Value cannot be empty.");

        var trimmed = version.Trim();
        var parts = trimmed.Split('.');

        if (parts.Length != 3)
            throw new FormatException(
                $"Invalid semantic version: '{trimmed}'. Expected format: MAJOR.MINOR.PATCH (got {parts.Length} part(s)).");

        if (!int.TryParse(parts[0], out var major) ||
            !int.TryParse(parts[1], out var minor) ||
            !int.TryParse(parts[2], out var patch))
            throw new FormatException(
                $"Invalid semantic version: '{trimmed}'. All parts must be non-negative integers.");

        if (major < 0 || minor < 0 || patch < 0)
            throw new FormatException(
                $"Invalid semantic version: '{trimmed}'. Version numbers cannot be negative.");

        return new SemanticVersion(major, minor, patch);
    }
}

/// <summary>
/// The type of version bump to apply, ordered from least to greatest impact.
/// Higher enum values override lower ones when combining multiple commits.
/// </summary>
public enum BumpType
{
    None  = 0, // No releasable commits (chore, docs, etc.)
    Patch = 1, // fix: — backwards-compatible bug fixes
    Minor = 2, // feat: — backwards-compatible new features
    Major = 3  // BREAKING CHANGE / "!" — incompatible API changes
}

/// <summary>
/// A parsed conventional commit message.
/// See https://www.conventionalcommits.org/
/// </summary>
public record Commit(
    string Type,          // e.g. "feat", "fix", "chore"
    string Description,   // The commit subject line (after the colon)
    bool IsBreaking,      // True if "!" suffix or "BREAKING CHANGE:" in body
    string? Scope = null, // Optional scope e.g. feat(api):
    string? Body = null   // Full raw message (subject + body)
);
